using BenchmarkDotNet.Attributes;
using TextAnalysis;

namespace Benchmarks;

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // ~200-word paragraph covering a realistic mix of word lengths
        var text =
            "The quick brown fox jumps over the lazy dog while the cat sits quietly on the warm windowsill " +
            "watching birds fly across the bright blue sky during a beautiful sunny afternoon in the countryside " +
            "where flowers bloom and trees sway gently in the breeze creating a peaceful atmosphere that everyone " +
            "enjoys especially children who love to play outside running through meadows and climbing hills until " +
            "the sun sets behind the mountains painting the horizon with shades of orange purple and gold while " +
            "families gather together for dinner sharing stories about their adventures and experiences throughout " +
            "the remarkable day that brought so much joy and happiness to all who participated in the wonderful " +
            "celebration of life nature and community bringing people closer together through shared moments of " +
            "laughter kindness and genuine connection that transcends ordinary everyday interactions fostering " +
            "deeper understanding appreciation and respect among neighbors friends and fellow citizens alike";
        _analyzer = new TextAnalyzer(text);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

